import{_ as a,o as s,c as e,aw as n}from"./chunks/framework.Dq2onT5h.js";const t=JSON.parse('{"title":"Block and Header Validity","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Block and Header Validity | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"reference/specs/block-validity.md","filePath":"reference/specs/block-validity.md","lastUpdated":1772446570000}');const o=a({name:"reference/specs/block-validity.md"},[["render",function(a,t,o,l,r,p){return s(),e("div",null,[...t[0]||(t[0]=[n('<h1 id="block-and-header-validity" tabindex="-1">Block and Header Validity <a class="header-anchor" href="#block-and-header-validity" aria-label="Permalink to &quot;Block and Header Validity&quot;">​</a></h1><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>Like all blockchains, chains are defined as the chain of <strong>valid</strong> blocks from the genesis, to the head. Thus, the block and header validity rules define the chain.</p><p>Verifying a block/header is done in 3 parts:</p><ol><li><p>Verify correct serialization according to the protobuf spec</p></li><li><p>Perform basic validation of the types</p></li><li><p>Perform verification of the new block against the previously accepted block</p></li></ol><p>Evolve uses a header/data separation architecture where headers and data can be validated independently. The system has moved from a multi-validator model to a single signer model for simplified sequencer management.</p><h2 id="basic-validation" tabindex="-1">Basic Validation <a class="header-anchor" href="#basic-validation" aria-label="Permalink to &quot;Basic Validation&quot;">​</a></h2><p>Each type contains a <code>.ValidateBasic()</code> method, which verifies that certain basic invariants hold. The <code>ValidateBasic()</code> calls are nested for each structure.</p><h3 id="signedheader-validation" tabindex="-1">SignedHeader Validation <a class="header-anchor" href="#signedheader-validation" aria-label="Permalink to &quot;SignedHeader Validation&quot;">​</a></h3><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#DBD7CA;">SignedHeader</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">ValidateBasic</span><span style="color:#767676;">()</span></span>\n<span class="line"><span style="color:#A0A0A0;">  // Make sure the SignedHeader&#39;s Header passes basic validation</span></span>\n<span class="line"><span style="color:#DBD7CA;">  Header</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">ValidateBasic</span><span style="color:#767676;">()</span></span>\n<span class="line"><span style="color:#DBD7CA;">    verify ProposerAddress not </span><span style="color:#B8A6FF;">nil</span></span>\n<span class="line"><span style="color:#A0A0A0;">  // Make sure the SignedHeader&#39;s signature passes basic validation</span></span>\n<span class="line"><span style="color:#DBD7CA;">  Signature</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">ValidateBasic</span><span style="color:#767676;">()</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // Ensure that someone signed the header</span></span>\n<span class="line"><span style="color:#DBD7CA;">    verify </span><span style="color:#94EEFF;">len</span><span style="color:#767676;">(</span><span style="color:#DBD7CA;">c</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">Signatures</span><span style="color:#767676;">)</span><span style="color:#DBD7CA;"> not </span><span style="color:#FFECB6;">0</span></span>\n<span class="line"><span style="color:#A0A0A0;">  // For based chains (sh.Signer.IsEmpty()), pass validation</span></span>\n<span class="line"><span style="color:#B8A6FF;">  if</span><span style="color:#888888;"> !</span><span style="color:#DBD7CA;">sh</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">Signer</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">IsEmpty</span><span style="color:#767676;">():</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // Verify the signer matches the proposer address</span></span>\n<span class="line"><span style="color:#DBD7CA;">    verify sh</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">Signer</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">Address </span><span style="color:#888888;">==</span><span style="color:#DBD7CA;"> sh</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">ProposerAddress</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // Verify signature using custom verifier if set, otherwise use default</span></span>\n<span class="line"><span style="color:#B8A6FF;">    if</span><span style="color:#DBD7CA;"> sh</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">verifier </span><span style="color:#888888;">!=</span><span style="color:#B8A6FF;"> nil</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#DBD7CA;">      verify sh</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">verifier</span><span style="color:#767676;">(</span><span style="color:#DBD7CA;">sh</span><span style="color:#767676;">)</span><span style="color:#888888;"> ==</span><span style="color:#B8A6FF;"> nil</span></span>\n<span class="line"><span style="color:#B8A6FF;">    else</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#DBD7CA;">      verify sh</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">Signature</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">Verify</span><span style="color:#767676;">(</span><span style="color:#DBD7CA;">sh</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">Signer</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">PubKey</span><span style="color:#767676;">,</span><span style="color:#DBD7CA;"> sh</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">Header</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">MarshalBinary</span><span style="color:#767676;">())</span></span></code></pre></div><h3 id="signeddata-validation" tabindex="-1">SignedData Validation <a class="header-anchor" href="#signeddata-validation" aria-label="Permalink to &quot;SignedData Validation&quot;">​</a></h3><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#DBD7CA;">SignedData</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">ValidateBasic</span><span style="color:#767676;">()</span></span>\n<span class="line"><span style="color:#A0A0A0;">  // Always passes basic validation for the Data itself</span></span>\n<span class="line"><span style="color:#DBD7CA;">  Data</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">ValidateBasic</span><span style="color:#767676;">()</span><span style="color:#A0A0A0;"> // always passes</span></span>\n<span class="line"><span style="color:#A0A0A0;">  // Make sure the signature is valid</span></span>\n<span class="line"><span style="color:#DBD7CA;">  Signature</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">ValidateBasic</span><span style="color:#767676;">()</span></span>\n<span class="line"><span style="color:#DBD7CA;">    verify </span><span style="color:#94EEFF;">len</span><span style="color:#767676;">(</span><span style="color:#DBD7CA;">c</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">Signatures</span><span style="color:#767676;">)</span><span style="color:#DBD7CA;"> not </span><span style="color:#FFECB6;">0</span></span>\n<span class="line"><span style="color:#A0A0A0;">  // Verify the signer</span></span>\n<span class="line"><span style="color:#DBD7CA;">  If </span><span style="color:#888888;">!</span><span style="color:#DBD7CA;">sd</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">Signer</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">IsEmpty</span><span style="color:#767676;">():</span></span>\n<span class="line"><span style="color:#DBD7CA;">    verify sd</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">Signature</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">Verify</span><span style="color:#767676;">(</span><span style="color:#DBD7CA;">sd</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">Signer</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">PubKey</span><span style="color:#767676;">,</span><span style="color:#DBD7CA;"> sd</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">Data</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">MarshalBinary</span><span style="color:#767676;">())</span></span></code></pre></div><h3 id="block-validation" tabindex="-1">Block Validation <a class="header-anchor" href="#block-validation" aria-label="Permalink to &quot;Block Validation&quot;">​</a></h3><p>Blocks are composed of SignedHeader and Data:</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;">// Block validation happens by validating header and data separately</span></span>\n<span class="line"><span style="color:#A0A0A0;">// then ensuring data hash matches</span></span>\n<span class="line"><span style="color:#DBD7CA;">verify SignedHeader</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">ValidateBasic</span><span style="color:#767676;">()</span><span style="color:#888888;"> ==</span><span style="color:#B8A6FF;"> nil</span></span>\n<span class="line"><span style="color:#DBD7CA;">verify Data</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">Hash</span><span style="color:#767676;">()</span><span style="color:#888888;"> ==</span><span style="color:#DBD7CA;"> SignedHeader</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">DataHash</span></span></code></pre></div><h2 id="verification-against-previous-block" tabindex="-1">Verification Against Previous Block <a class="header-anchor" href="#verification-against-previous-block" aria-label="Permalink to &quot;Verification Against Previous Block&quot;">​</a></h2><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#DBD7CA;">SignedHeader</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">Verify</span><span style="color:#767676;">(</span><span style="color:#DBD7CA;">untrustedHeader </span><span style="color:#888888;">*</span><span style="color:#DBD7CA;">SignedHeader</span><span style="color:#767676;">)</span></span>\n<span class="line"><span style="color:#A0A0A0;">  // Basic validation is handled by go-header before this</span></span>\n<span class="line"><span style="color:#DBD7CA;">  Header</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">Verify</span><span style="color:#767676;">(</span><span style="color:#DBD7CA;">untrustedHeader</span><span style="color:#767676;">)</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // Verify height sequence</span></span>\n<span class="line"><span style="color:#B8A6FF;">    if</span><span style="color:#DBD7CA;"> untrustedHeader</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">Height </span><span style="color:#888888;">!=</span><span style="color:#DBD7CA;"> h</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">Height </span><span style="color:#888888;">+</span><span style="color:#FFECB6;"> 1</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#B8A6FF;">      if</span><span style="color:#DBD7CA;"> untrustedHeader</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">Height </span><span style="color:#888888;">&gt;</span><span style="color:#DBD7CA;"> h</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">Height </span><span style="color:#888888;">+</span><span style="color:#FFECB6;"> 1</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#B8A6FF;">        return</span><span style="color:#DBD7CA;"> soft verification failure</span></span>\n<span class="line"><span style="color:#B8A6FF;">      return</span><span style="color:#B8A6FF;"> error</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">headers are not adjacent</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // Verify the link to previous header</span></span>\n<span class="line"><span style="color:#DBD7CA;">    verify untrustedHeader</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">LastHeaderHash </span><span style="color:#888888;">==</span><span style="color:#DBD7CA;"> h</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">Header</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">Hash</span><span style="color:#767676;">()</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // Note: ValidatorHash field exists for compatibility but is not validated</span></span></code></pre></div><h2 id="data" tabindex="-1"><a href="https://github.com/evstack/ev-node/blob/main/types/data.go" target="_blank" rel="noreferrer">Data</a> <a class="header-anchor" href="#data" aria-label="Permalink to &quot;[Data](https://github.com/evstack/ev-node/blob/main/types/data.go)&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Field Name</strong></th><th><strong>Valid State</strong></th><th><strong>Validation</strong></th></tr></thead><tbody><tr><td>Txs</td><td>Transaction data of the block</td><td>Data.Hash() == SignedHeader.DataHash</td></tr><tr><td>Metadata</td><td>Optional p2p gossiping metadata</td><td>Not validated</td></tr></tbody></table><h2 id="signedheader" tabindex="-1"><a href="https://github.com/evstack/ev-node/blob/main/types/signed_header.go" target="_blank" rel="noreferrer">SignedHeader</a> <a class="header-anchor" href="#signedheader" aria-label="Permalink to &quot;[SignedHeader](https://github.com/evstack/ev-node/blob/main/types/signed_header.go)&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Field Name</strong></th><th><strong>Valid State</strong></th><th><strong>Validation</strong></th></tr></thead><tbody><tr><td>Header</td><td>Valid header for the block</td><td><code>Header</code> passes <code>ValidateBasic()</code> and <code>Verify()</code></td></tr><tr><td>Signature</td><td>Valid signature from the single sequencer</td><td><code>Signature</code> passes <code>ValidateBasic()</code>, verified against signer</td></tr><tr><td>Signer</td><td>Information about who signed the header</td><td>Must match ProposerAddress if not empty (based chain case)</td></tr><tr><td>verifier</td><td>Optional custom signature verification function</td><td>Used instead of default verification if set</td></tr></tbody></table><h2 id="header" tabindex="-1"><a href="https://github.com/evstack/ev-node/blob/main/types/header.go" target="_blank" rel="noreferrer">Header</a> <a class="header-anchor" href="#header" aria-label="Permalink to &quot;[Header](https://github.com/evstack/ev-node/blob/main/types/header.go)&quot;">​</a></h2><p><em><strong>Note</strong></em>: Evolve has moved to a single signer model. The multi-validator architecture has been replaced with a simpler single sequencer approach.</p><table tabindex="0"><thead><tr><th><strong>Field Name</strong></th><th><strong>Valid State</strong></th><th><strong>Validation</strong></th></tr></thead><tbody><tr><td><strong>BaseHeader</strong></td><td></td><td></td></tr><tr><td>Height</td><td>Height of the previous accepted header, plus 1.</td><td>checked in the `Verify()`` step</td></tr><tr><td>Time</td><td>Timestamp of the block</td><td>Not validated in Evolve</td></tr><tr><td>ChainID</td><td>The hard-coded ChainID of the chain</td><td>Should be checked as soon as the header is received</td></tr><tr><td><strong>Header</strong> .</td><td></td><td></td></tr><tr><td>Version</td><td>unused</td><td></td></tr><tr><td>LastHeaderHash</td><td>The hash of the previous accepted block</td><td>checked in the `Verify()`` step</td></tr><tr><td>DataHash</td><td>Correct hash of the block&#39;s Data field</td><td>checked in the `ValidateBasic()`` step</td></tr><tr><td>AppHash</td><td>The correct state root after executing the block&#39;s transactions against the accepted state</td><td>checked during block execution</td></tr><tr><td>ProposerAddress</td><td>Address of the expected proposer</td><td>Must match Signer.Address in SignedHeader</td></tr><tr><td>ValidatorHash</td><td>Compatibility field for Tendermint light client</td><td>Not validated</td></tr></tbody></table><h2 id="signer" tabindex="-1"><a href="https://github.com/evstack/ev-node/blob/main/types/signed_header.go" target="_blank" rel="noreferrer">Signer</a> <a class="header-anchor" href="#signer" aria-label="Permalink to &quot;[Signer](https://github.com/evstack/ev-node/blob/main/types/signed_header.go)&quot;">​</a></h2><p>The Signer type replaces the previous ValidatorSet for single sequencer operation:</p><table tabindex="0"><thead><tr><th><strong>Field Name</strong></th><th><strong>Valid State</strong></th><th><strong>Validation</strong></th></tr></thead><tbody><tr><td>PubKey</td><td>Public key of the signer</td><td>Must not be nil if Signer is not empty</td></tr><tr><td>Address</td><td>Address derived from the public key</td><td>Must match ProposerAddress</td></tr></tbody></table>',27)])])}]]);export{t as __pageData,o as default};
